[asy]
unitsize (0.8 cm);

pair A, B, C, D, O;

A = (3,4);
C = (7,10);
O = (A + C)/2;
B = O + abs(O - A)*dir(170);
D = O + abs(O - A)*dir(350);

draw(Circle(O,abs(O - A)));
draw(A--C);
draw(B--D);
draw(A--B--C--D--cycle);

label("$A$", A, SW);
label("$B$", B, W);
label("$C$", C, NE);
label("$D$", D, E);

dot(O);
[/asy]

